/* ============ Load Model Weights ============ */

int read_int_from(char **p) {
    char *d;
    int v;
    d = *p;
    v = (d[0] & 0xFF) | ((d[1] & 0xFF) << 8) | ((d[2] & 0xFF) << 16) | ((d[3] & 0xFF) << 24);
    *p = d + 4;
    return v;
}

/* Simple string compare (no strcmp needed) */
int str_eq(char *a, char *b) {
    while (*a && *b) {
        if (*a != *b) return 0;
        a = a + 1;
        b = b + 1;
    }
    return *a == *b;
}

